138→
139→## Task 4: Token management functions
140→
141→Write `convex/tokens.ts`:
142→
143→```typescript
144→import { v } from "convex/values";
145→import { mutation, query, internalMutation } from "./_generated/server";
146→import { getAuthUserId } from "@convex-dev/auth/server";
147→
148→// Uniform random string generation (no modular bias)
149→function secureRandomString(length: number): string {
150→  const chars = "REDACTED";
151→  const max = Math.floor(256 / chars.length) * chars.length;
152→  const result: string[] = [];
153→  while (result.length < length) {
154→    const array = new Uint8Array(length - result.length);
155→    crypto.getRandomValues(array);
156→    for (const b of array) {
157→      if (b < max && result.length < length) {
158→        result.push(chars[b % chars.length]);
159→      }
160→    }
161→  }
162→  return result.join("");
163→}
164→
165→function generateToken(): string {
166→  return "nrg_" + secureRandomString(48);
167→}
168→
169→function generateCode(): string {
170→  return secureRandomString(32);
171→}
172→
173→// Called by /cli-auth page after Google OAuth.
174→// Resolves userId from session — no argument needed.
175→export const createAuthCode = mutation({
176→  args: {},
177→  handler: async (ctx) => {
178→    const userId = await getAuthUserId(ctx);
179→    if (!userId) throw new Error("Not authenticated");
180→
181→    const code = generateCode();
182→    const now = Date.now();
183→    await ctx.db.insert("authCodes", {
184→      code,
185→      userId,
186→      expiresAt: now + 5 * 60 * 1000, // 5 minutes
187→      used: false,
188→    });
189→    return { code };
190→  },
191→});
192→
193→// Called only by exchangeCode HTTP action (internal)
194→export const exchangeCodeForToken = internalMutation({
195→  args: { code: v.string(), deviceName: v.optional(v.string()) },
196→  handler: async (ctx, { code, deviceName }) => {
197→    const authCode = await ctx.db
198→      .query("authCodes")
199→      .withIndex("by_code", (q) => q.eq("code", code))
200→      .unique();
201→
202→    if (!authCode || authCode.used || authCode.expiresAt < Date.now()) {
203→      return null;
204→    }
205→
206→    await ctx.db.patch(authCode._id, { used: true });
207→
208→    const user = await ctx.db.get(authCode.userId);
209→    if (!user) return null;
210→
211→    const token = generateToken();
212→    const now = Date.now();
213→    await ctx.db.insert("apiTokens", {
214→      userId: authCode.userId,
215→      token,
216→      deviceName,
217→      createdAt: now,
218→      lastUsedAt: now,
219→    });
220→
221→    return { token, email: user.email, name: user.name };
222→  },
223→});
224→
225→// Called by validateToken HTTP action (read-only)
226→export const getTokenUser = query({
227→  args: { token: v.string() },
228→  handler: async (ctx, { token }) => {
229→    const apiToken = await ctx.db
230→      .query("apiTokens")
231→      .withIndex("by_token", (q) => q.eq("token", token))
232→      .unique();
233→
234→    if (!apiToken) return { valid: false as const };
235→    if (apiToken.expiresAt && apiToken.expiresAt < Date.now()) {
236→      return { valid: false as const };
237→    }
238→
239→    const user = await ctx.db.get(apiToken.userId);
240→    if (!user) return { valid: false as const };
241→
242→    return {
243→      valid: true as const,
244→      tokenId: apiToken._id,
245→      user: { email: user.email, name: user.name },
246→    };
247→  },
248→});
249→
250→// Update lastUsedAt (fire-and-forget, called after validation)
251→export const touchTokenLastUsed = internalMutation({
252→  args: { tokenId: v.id("apiTokens") },
253→  handler: async (ctx, { tokenId }) => {
254→    await ctx.db.patch(tokenId, { lastUsedAt: Date.now() });
255→  },
256→});
257→
258→// Called only by revokeToken HTTP action (internal)
259→export const deleteToken = internalMutation({
260→  args: { token: v.string() },
261→  handler: async (ctx, { token }) => {
262→    const apiToken = await ctx.db
263→      .query("apiTokens")
264→      .withIndex("by_token", (q) => q.eq("token", token))
265→      .unique();
266→    if (apiToken) {
267→      await ctx.db.delete(apiToken._id);
268→    }
269→  },
270→});
271→```
272→
273→Write `convex/users.ts`:
274→
275→```typescript
276→import { query } from "./_generated/server";
277→import { getAuthUserId } from "@convex-dev/auth/server";
278→
279→export const currentUser = query({
280→  handler: async (ctx) => {
281→    const userId = await getAuthUserId(ctx);
282→    if (!userId) return null;
283→    const user = await ctx.db.get(userId);
284→    return user;
285→  },
286→});
287→```
288→
289→```bash
290→npx convex dev --once
291→git add convex/tokens.ts convex/users.ts
292→git commit -m "feat: add token management functions"
293→```
