297→## Task 5: HTTP action routes
298→
299→Update `convex/http.ts` — these are the endpoints the CLI calls:
300→
301→```typescript
302→import { httpRouter } from "convex/server";
303→import { httpAction } from "./_generated/server";
304→import { internal, api } from "./_generated/api";
305→import { auth } from "./auth";
306→
307→const http = httpRouter();
308→
309→auth.addHttpRoutes(http);
310→
311→// POST /api/validate-token
312→// CLI calls this on every command to verify the user's token
313→http.route({
314→  path: "/api/validate-token",
315→  method: "POST",
316→  handler: httpAction(async (ctx, request) => {
317→    const { token } = await request.json();
318→    if (!token || typeof token !== "string") {
319→      return new Response(
320→        JSON.stringify({ valid: false, error: "missing token" }),
321→        { status: 400, headers: { "Content-Type": "application/json" } },
322→      );
323→    }
324→
325→    const result = await ctx.runQuery(api.tokens.getTokenUser, { token });
326→
327→    if (result.valid && result.tokenId) {
328→      await ctx.runMutation(internal.tokens.touchTokenLastUsed, {
329→        tokenId: result.tokenId,
330→      });
331→    }
332→
333→    return new Response(
334→      JSON.stringify(
335→        result.valid ? { valid: true, user: result.user } : { valid: false },
336→      ),
337→      { status: 200, headers: { "Content-Type": "application/json" } },
338→    );
339→  }),
340→});
341→
342→// POST /api/exchange-code
343→// CLI exchanges the one-time auth code for a long-lived API token
344→http.route({
345→  path: "/api/exchange-code",
346→  method: "POST",
347→  handler: httpAction(async (ctx, request) => {
348→    const { code, deviceName } = await request.json();
349→    if (!code || typeof code !== "string") {
350→      return new Response(
351→        JSON.stringify({ error: "missing code" }),
352→        { status: 400, headers: { "Content-Type": "application/json" } },
353→      );
354→    }
355→
356→    const result = await ctx.runMutation(
357→      internal.tokens.exchangeCodeForToken,
358→      { code, deviceName },
359→    );
360→
361→    if (!result) {
362→      return new Response(
363→        JSON.stringify({ error: "invalid or expired code" }),
364→        { status: 401, headers: { "Content-Type": "application/json" } },
365→      );
366→    }
367→
368→    return new Response(JSON.stringify(result), {
369→      status: 200,
370→      headers: { "Content-Type": "application/json" },
371→    });
372→  }),
373→});
374→
375→// POST /api/revoke-token
376→// CLI calls this on `nurge account logout`
377→http.route({
378→  path: "/api/revoke-token",
379→  method: "POST",
380→  handler: httpAction(async (ctx, request) => {
381→    const { token } = await request.json();
382→    if (!token || typeof token !== "string") {
383→      return new Response(
384→        JSON.stringify({ error: "missing token" }),
385→        { status: 400, headers: { "Content-Type": "application/json" } },
386→      );
387→    }
388→
389→    await ctx.runMutation(internal.tokens.deleteToken, { token });
390→
391→    return new Response(JSON.stringify({ ok: true }), {
392→      status: 200,
393→      headers: { "Content-Type": "application/json" },
394→    });
395→  }),
396→});
397→
398→export default http;
399→```
400→
401→Test with curl after deploying:
402→```bash
403→npx convex dev --once
404→
405→curl -X POST https://<deployment>.convex.site/api/validate-token \
406→  -H "Content-Type: application/json" \
407→  -d '{"token": "nrg_bogus"}'
408→# Expected: {"valid":false}
409→```
410→
411→```bash
412→git add convex/http.ts
413→git commit -m "feat: add HTTP action routes for CLI auth"
414→```
