418→## Task 6: CLI auth page
419→
420→Write `src/app/providers.tsx`:
421→
422→```tsx
423→"use client";
424→
425→import { ConvexReactClient } from "convex/react";
426→import { ConvexAuthNextjsProvider } from "@convex-dev/auth/nextjs";
427→import { ReactNode } from "react";
428→
429→const convex = new ConvexReactClient(process.env.NEXT_PUBLIC_CONVEX_URL!);
430→
431→export function Providers({ children }: { children: ReactNode }) {
432→  return (
433→    <ConvexAuthNextjsProvider client={convex}>
434→      {children}
435→    </ConvexAuthNextjsProvider>
