438→```
439→
440→Update `src/app/layout.tsx` to wrap children:
441→
442→```tsx
443→import { Providers } from "./providers";
444→// ... existing imports
445→
446→export default function RootLayout({ children }: { children: React.ReactNode }) {
447→  return (
448→    <html lang="en">
