450→        <Providers>{children}</Providers>
451→      </body>
452→    </html>
453→  );
454→}
455→```
456→
457→Write `src/app/cli-auth/page.tsx`:
458→
459→```tsx
460→"use client";
461→
462→import { useSearchParams } from "next/navigation";
463→import { useAuthActions } from "@convex-dev/auth/react";
464→import { useConvexAuth, useMutation } from "convex/react";
465→import { api } from "../../../convex/_generated/api";
466→import { useEffect, useState, Suspense } from "react";
467→
468→function CliAuthContent() {
469→  const searchParams = useSearchParams();
470→  const port = searchParams.get("port");
471→  const state = searchParams.get("state");
472→  const { signIn } = useAuthActions();
473→  const { isAuthenticated, isLoading } = useConvexAuth();
474→  const createAuthCode = useMutation(api.tokens.createAuthCode);
475→  const [status, setStatus] = useState<
476→    "login" | "redirecting" | "done" | "error"
477→  >("login");
478→  const [error, setError] = useState<string | null>(null);
479→
480→  // After Google auth completes, create code and redirect to CLI
481→  useEffect(() => {
482→    if (!isAuthenticated || status !== "login" || !port || !state) return;
483→
484→    async function handleRedirect() {
485→      try {
486→        setStatus("redirecting");
487→        const { code } = await createAuthCode({});
488→        window.location.href = `http://localhost:${port}/callback?code=${code}&state=${state}`;
489→        setStatus("done");
490→      } catch (e) {
491→        setError(e instanceof Error ? e.message : "Unknown error");
492→        setStatus("error");
493→      }
494→    }
495→
496→    handleRedirect();
497→  }, [isAuthenticated, status, port, state, createAuthCode]);
498→
499→  if (!port || !state) {
500→    return (
501→      <div className="min-h-screen flex items-center justify-center">
502→        <p className="text-red-500">
503→          Missing parameters. Run <code>nurge init</code> to start.
504→        </p>
505→      </div>
506→    );
507→  }
508→
509→  if (isLoading) {
510→    return (
511→      <div className="min-h-screen flex items-center justify-center">
512→        <p>Loading...</p>
513→      </div>
514→    );
515→  }
516→
517→  if (status === "done") {
518→    return (
519→      <div className="min-h-screen flex items-center justify-center">
520→        <div className="text-center">
521→          <h2 className="text-2xl font-bold mb-2">Success!</h2>
522→          <p className="text-gray-600">
523→            You can close this tab and return to the terminal.
524→          </p>
525→        </div>
526→      </div>
527→    );
528→  }
529→
530→  if (status === "error") {
531→    return (
532→      <div className="min-h-screen flex items-center justify-center">
533→        <div className="text-center">
534→          <h2 className="text-2xl font-bold text-red-600 mb-2">Error</h2>
535→          <p className="text-gray-600">{error}</p>
536→        </div>
537→      </div>
538→    );
539→  }
540→
541→  if (status === "redirecting") {
542→    return (
543→      <div className="min-h-screen flex items-center justify-center">
544→        <p>Redirecting to terminal...</p>
545→      </div>
546→    );
547→  }
548→
549→  return (
550→    <div className="min-h-screen flex items-center justify-center bg-gray-50">
551→      <div className="max-w-sm w-full p-8 bg-white rounded-lg shadow-md text-center">
552→        <h1 className="text-2xl font-bold mb-2">nurge</h1>
553→        <p className="text-gray-600 mb-6">Sign in to continue</p>
554→        <button
555→          onClick={() => void signIn("google")}
556→          className="w-full bg-black text-white py-3 px-4 rounded-md hover:bg-gray-800 transition-colors"
557→        >
558→          Sign in with Google
559→        </button>
560→      </div>
561→    </div>
562→  );
563→}
564→
565→export default function CliAuthPage() {
566→  return (
567→    <Suspense
568→      fallback={
569→        <div className="min-h-screen flex items-center justify-center">
570→          <p>Loading...</p>
571→        </div>
572→      }
573→    >
574→      <CliAuthContent />
575→    </Suspense>
576→  );
577→}
578→```
579→
580→Test locally:
581→```bash
582→npm run dev
583→# In another terminal:
584→npx convex dev
585→```
586→
587→Open `http://localhost:3000/cli-auth?port=12345&state=teststate`. Should show the sign-in button. After Google auth, it redirects to `localhost:12345/callback?code=...&state=teststate` (will fail since no CLI server — that's expected).
588→
589→```bash
590→git add src/app/cli-auth/ src/app/providers.tsx src/app/layout.tsx
591→git commit -m "feat: add CLI auth page with Google OAuth flow"
592→```
