629→        <div className="space-y-4">
630→          <div>
631→            <label className="text-sm text-gray-500">Name</label>
632→            <p className="text-lg">{user?.name ?? "—"}</p>
633→          </div>
634→          <div>
635→            <label className="text-sm text-gray-500">Email</label>
636→            <p className="text-lg">{user?.email ?? "—"}</p>
637→          </div>
638→        </div>
639→        <button
640→          onClick={() => void signOut()}
641→          className="mt-8 text-red-600 hover:text-red-800 text-sm"
