## Task 4: Token management functions

Write `convex/tokens.ts`:

```typescript
import { v } from "convex/values";
import { mutation, query, internalMutation } from "./_generated/server";
import { getAuthUserId } from "@convex-dev/auth/server";

// Uniform random string generation (no modular bias)
function secureRandomString(length: number): string {
  const chars = "REDACTED";
  const max = Math.floor(256 / chars.length) * chars.length;
  const result: string[] = [];
  while (result.length < length) {
    const array = new Uint8Array(length - result.length);
    crypto.getRandomValues(array);
    for (const b of array) {
      if (b < max && result.length < length) {
        result.push(chars[b % chars.length]);
      }
    }
  }
  return result.join("");
}

function generateToken(): string {
  return "nrg_" + secureRandomString(48);
}

function generateCode(): string {
  return secureRandomString(32);
}

// Called by /cli-auth page after Google OAuth.
// Resolves userId from session — no argument needed.
export const createAuthCode = mutation({
  args: {},
  handler: async (ctx) => {
    const userId = await getAuthUserId(ctx);
    if (!userId) throw new Error("Not authenticated");

    const code = generateCode();
    const now = Date.now();
    await ctx.db.insert("authCodes", {
      code,
      userId,
      expiresAt: now + 5 * 60 * 1000, // 5 minutes
      used: false,
    });
    return { code };
  },
});

// Called only by exchangeCode HTTP action (internal)
export const exchangeCodeForToken = internalMutation({
  args: { code: v.string(), deviceName: v.optional(v.string()) },
  handler: async (ctx, { code, deviceName }) => {
    const authCode = await ctx.db
      .query("authCodes")
      .withIndex("by_code", (q) => q.eq("code", code))
      .unique();

    if (!authCode || authCode.used || authCode.expiresAt < Date.now()) {
      return null;
    }

    await ctx.db.patch(authCode._id, { used: true });

    const user = await ctx.db.get(authCode.userId);
    if (!user) return null;

    const token = generateToken();
    const now = Date.now();
    await ctx.db.insert("apiTokens", {
      userId: authCode.userId,
      token,
      deviceName,
      createdAt: now,
      lastUsedAt: now,
    });

    return { token, email: user.email, name: user.name };
  },
});

// Called by validateToken HTTP action (read-only)
export const getTokenUser = query({
  args: { token: v.string() },
  handler: async (ctx, { token }) => {
    const apiToken = await ctx.db
      .query("apiTokens")
      .withIndex("by_token", (q) => q.eq("token", token))
      .unique();

    if (!apiToken) return { valid: false as const };
    if (apiToken.expiresAt && apiToken.expiresAt < Date.now()) {
      return { valid: false as const };
    }

    const user = await ctx.db.get(apiToken.userId);
    if (!user) return { valid: false as const };

    return {
      valid: true as const,
      tokenId: apiToken._id,
      user: { email: user.email, name: user.name },
    };
  },
});

// Update lastUsedAt (fire-and-forget, called after validation)
export const touchTokenLastUsed = internalMutation({
  args: { tokenId: v.id("apiTokens") },
  handler: async (ctx, { tokenId }) => {
    await ctx.db.patch(tokenId, { lastUsedAt: Date.now() });
  },
});

// Called only by revokeToken HTTP action (internal)
export const deleteToken = internalMutation({
  args: { token: v.string() },
  handler: async (ctx, { token }) => {
    const apiToken = await ctx.db
      .query("apiTokens")
      .withIndex("by_token", (q) => q.eq("token", token))
      .unique();
    if (apiToken) {
      await ctx.db.delete(apiToken._id);
    }
  },
});
```

