## Task 5: HTTP action routes

Update `convex/http.ts` — these are the endpoints the CLI calls:

```typescript
import { httpRouter } from "convex/server";
import { httpAction } from "./_generated/server";
import { internal, api } from "./_generated/api";
import { auth } from "./auth";

const http = httpRouter();

auth.addHttpRoutes(http);

// POST /api/validate-token
// CLI calls this on every command to verify the user's token
http.route({
  path: "/api/validate-token",
  method: "POST",
  handler: httpAction(async (ctx, request) => {
    const { token } = await request.json();
    if (!token || typeof token !== "string") {
      return new Response(
        JSON.stringify({ valid: false, error: "missing token" }),
        { status: 400, headers: { "Content-Type": "application/json" } },
      );
    }

    const result = await ctx.runQuery(api.tokens.getTokenUser, { token });

    if (result.valid && result.tokenId) {
      await ctx.runMutation(internal.tokens.touchTokenLastUsed, {
        tokenId: result.tokenId,
      });
    }

    return new Response(
      JSON.stringify(
        result.valid ? { valid: true, user: result.user } : { valid: false },
      ),
      { status: 200, headers: { "Content-Type": "application/json" } },
    );
  }),
});

// POST /api/exchange-code
// CLI exchanges the one-time auth code for a long-lived API token
http.route({
  path: "/api/exchange-code",
  method: "POST",
  handler: httpAction(async (ctx, request) => {
    const { code, deviceName } = await request.json();
    if (!code || typeof code !== "string") {
      return new Response(
        JSON.stringify({ error: "missing code" }),
        { status: 400, headers: { "Content-Type": "application/json" } },
      );
    }

    const result = await ctx.runMutation(
      internal.tokens.exchangeCodeForToken,
      { code, deviceName },
    );

    if (!result) {
      return new Response(
        JSON.stringify({ error: "invalid or expired code" }),
        { status: 401, headers: { "Content-Type": "application/json" } },
      );
    }

    return new Response(JSON.stringify(result), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }),
});

// POST /api/revoke-token
// CLI calls this on `nurge account logout`
http.route({
  path: "/api/revoke-token",
  method: "POST",
  handler: httpAction(async (ctx, request) => {
    const { token } = await request.json();
    if (!token || typeof token !== "string") {
      return new Response(
        JSON.stringify({ error: "missing token" }),
        { status: 400, headers: { "Content-Type": "application/json" } },
      );
    }

    await ctx.runMutation(internal.tokens.deleteToken, { token });

    return new Response(JSON.stringify({ ok: true }), {
      status: 200,
      headers: { "Content-Type": "application/json" },
    });
  }),
});

export default http;
```

