```tsx
"use client";

import { useSearchParams } from "next/navigation";
import { useAuthActions } from "@convex-dev/auth/react";
import { useConvexAuth, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { useEffect, useState, Suspense } from "react";

function CliAuthContent() {
  const searchParams = useSearchParams();
  const port = searchParams.get("port");
  const state = searchParams.get("state");
  const { signIn } = useAuthActions();
  const { isAuthenticated, isLoading } = useConvexAuth();
  const createAuthCode = useMutation(api.tokens.createAuthCode);
  const [status, setStatus] = useState<
    "login" | "redirecting" | "done" | "error"
  >("login");
  const [error, setError] = useState<string | null>(null);

  // After Google auth completes, create code and redirect to CLI
  useEffect(() => {
    if (!isAuthenticated || status !== "login" || !port || !state) return;

    async function handleRedirect() {
      try {
        setStatus("redirecting");
        const { code } = await createAuthCode({});
        window.location.href = `http://localhost:${port}/callback?code=${code}&state=${state}`;
        setStatus("done");
      } catch (e) {
        setError(e instanceof Error ? e.message : "Unknown error");
        setStatus("error");
      }
    }

    handleRedirect();
  }, [isAuthenticated, status, port, state, createAuthCode]);

  if (!port || !state) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-red-500">
          Missing parameters. Run <code>nurge init</code> to start.
        </p>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p>Loading...</p>
      </div>
    );
  }

  if (status === "done") {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold mb-2">Success!</h2>
          <p className="text-gray-600">
            You can close this tab and return to the terminal.
          </p>
        </div>
      </div>
    );
  }

  if (status === "error") {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-bold text-red-600 mb-2">Error</h2>
          <p className="text-gray-600">{error}</p>
        </div>
      </div>
    );
  }

  if (status === "redirecting") {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p>Redirecting to terminal...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="max-w-sm w-full p-8 bg-white rounded-lg shadow-md text-center">
        <h1 className="text-2xl font-bold mb-2">nurge</h1>
        <p className="text-gray-600 mb-6">Sign in to continue</p>
        <button
          onClick={() => void signIn("google")}
          className="w-full bg-black text-white py-3 px-4 rounded-md hover:bg-gray-800 transition-colors"
        >
          Sign in with Google
        </button>
      </div>
    </div>
  );
}

export default function CliAuthPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen flex items-center justify-center">
          <p>Loading...</p>
        </div>
      }
    >
      <CliAuthContent />
    </Suspense>
  );
}
```

