 1→package email
 2→
 3→import (
 4→	"encoding/base64"
 5→	"fmt"
 6→	"strings"
 7→
 8→	gm "google.golang.org/api/gmail/v1"
 9→)
10→
11→// SendOptions holds the fields for composing an email.
12→type SendOptions struct {
13→	To      string // recipient email
14→	Cc      string // optional CC
15→	Subject string
16→	Body    string // plain text body
17→}
18→
19→// Send sends an email via the Gmail API.
20→func Send(srv *gm.Service, from string, opts SendOptions) (string, error) {
21→	if opts.To == "" {
22→		return "", fmt.Errorf("recipient (--to) is required")
23→	}
24→	if opts.Subject == "" {
25→		return "", fmt.Errorf("subject (--subject) is required")
26→	}
27→	if opts.Body == "" {
28→		return "", fmt.Errorf("body (--body) is required")
29→	}
30→
31→	raw := buildRawMessage(from, opts)
32→	msg := &gm.Message{
33→		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
34→	}
35→
36→	sent, err := srv.Users.Messages.Send("me", msg).Do()
37→	if err != nil {
38→		return "", fmt.Errorf("sending email: %w", err)
39→	}
40→
41→	return sent.Id, nil
42→}
43→
44→func buildRawMessage(from string, opts SendOptions) string {
45→	var b strings.Builder
46→	b.WriteString("From: " + from + "\r\n")
47→	b.WriteString("To: " + opts.To + "\r\n")
48→	if opts.Cc != "" {
49→		b.WriteString("Cc: " + opts.Cc + "\r\n")
50→	}
51→	b.WriteString("Subject: " + opts.Subject + "\r\n")
52→	b.WriteString("MIME-Version: 1.0\r\n")
53→	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
54→	b.WriteString("\r\n")
55→	b.WriteString(opts.Body)
56→	return b.String()
57→}
