  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"os"
  8→
  9→	"golang.org/x/oauth2"
 10→	"golang.org/x/oauth2/google"
 11→	"google.golang.org/api/gmail/v1"
 12→	"google.golang.org/api/option"
 13→)
 14→
 15→const (
 16→	gmailTokenPath = ".nurge/connectors/gmail/token.json"
 17→	gmailCredsPath = ".nurge/connectors/gmail/credentials.json"
 18→)
 19→
 20→type gmailConnector struct {
 21→	credentials string // optional override path for credentials.json
 22→}
 23→
 24→// NewGmail creates a new Gmail connector.
 25→func NewGmail(credentials string) Connector {
 26→	return &gmailConnector{credentials: credentials}
 27→}
 28→
 29→func (g *gmailConnector) ID() string   { return "gmail" }
 30→func (g *gmailConnector) Name() string { return "Gmail" }
 31→func (g *gmailConnector) Type() string { return "email" }
 32→
 33→func (g *gmailConnector) Connect(ctx context.Context) (*Result, error) {
 34→	// Load OAuth client credentials: custom path > local file > bundled
 35→	credsData, err := g.loadCredentials()
 36→	if err != nil {
 37→		return nil, err
 38→	}
 39→
 40→	oauthCfg, err := google.ConfigFromJSON(credsData,
 41→		gmail.GmailReadonlyScope,
 42→		gmail.GmailSendScope,
 43→		gmail.GmailModifyScope,
 44→	)
 45→	if err != nil {
 46→		return nil, fmt.Errorf("parsing credentials: %w", err)
 47→	}
 48→
 49→	// Run shared OAuth flow
 50→	token, err := OAuthFlow(ctx, oauthCfg, oauth2.SetAuthURLParam("prompt", "select_account"))
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→
 55→	// Save token
 56→	if err := os.MkdirAll(".nurge/connectors/gmail", 0755); err != nil {
 57→		return nil, fmt.Errorf("creating gmail connector dir: %w", err)
 58→	}
 59→	if err := saveToken(gmailTokenPath, token); err != nil {
 60→		return nil, fmt.Errorf("saving token: %w", err)
 61→	}
 62→
 63→	// Get the user's email address
 64→	client := oauthCfg.Client(ctx, token)
 65→	srv, err := gmail.NewService(ctx, option.WithHTTPClient(client))
 66→	if err != nil {
 67→		return nil, fmt.Errorf("creating Gmail service: %w", err)
 68→	}
 69→
 70→	profile, err := srv.Users.GetProfile("me").Do()
 71→	if err != nil {
 72→		return nil, fmt.Errorf("getting Gmail profile: %w", err)
 73→	}
 74→
 75→	return &Result{
 76→		Account: profile.EmailAddress,
 77→		Token:   token,
 78→	}, nil
 79→}
 80→
 81→func (g *gmailConnector) loadCredentials() ([]byte, error) {
 82→	// 1. Explicit path from --credentials flag
 83→	if g.credentials != "" {
 84→		data, err := os.ReadFile(g.credentials)
 85→		if err != nil {
 86→			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
 87→		}
 88→		return data, nil
 89→	}
 90→
 91→	// 2. Local file in project
 92→	if data, err := os.ReadFile(gmailCredsPath); err == nil {
 93→		return data, nil
 94→	}
 95→
 96→	// 3. Bundled credentials
 97→	if len(BundledCredentials) > 0 {
 98→		return BundledCredentials, nil
 99→	}
100→
101→	return nil, fmt.Errorf("no Gmail credentials found — run `nurge init --credentials /path/to/credentials.json`")
102→}
103→
104→func saveToken(path string, token *oauth2.Token) error {
105→	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
106→	if err != nil {
107→		return err
108→	}
109→	defer f.Close()
110→	return json.NewEncoder(f).Encode(token)
111→}
