 36→
 37→	registry := connector.DefaultRegistry()
 38→	reader := bufio.NewReader(os.Stdin)
 39→
 40→	fmt.Println()
 41→	fmt.Println("  Connect your stack:")
 42→
 43→	for {
 44→		// Show menu
 45→		fmt.Println()
 46→		fmt.Println("    Email (required)")
 47→		for i, c := range registry {
 48→			if c.Type != "email" {
 49→				continue
 50→			}
 51→			status := ""
 52→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
 53→				status = fmt.Sprintf(" \033[32m✓\033[0m %s", cs.Account)
 54→			}
