 56→		}
 57→
 58→		fmt.Println()
 59→		fmt.Println("    CRM (optional — enriches contacts with deal & pipeline data)")
 60→		for i, c := range registry {
 61→			if c.Type != "crm" {
 62→				continue
 63→			}
 64→			status := ""
 65→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
