 74→		input, err := reader.ReadString('\n')
 75→		if err != nil {
 76→			return fmt.Errorf("reading input: %w", err)
 77→		}
 78→		input = strings.TrimSpace(input)
 79→
 80→		if input == "done" {
 81→			// Check Gmail is connected
