 83→				fmt.Println()
 84→				fmt.Print("  Gmail is required — it's how nurge reads your outbound history.\n  Connect now? [Y/n] ")
 85→				yn, _ := reader.ReadString('\n')
 86→				yn = strings.TrimSpace(strings.ToLower(yn))
 87→				if yn == "n" || yn == "no" {
 88→					return fmt.Errorf("gmail is required to use nurge")
 89→				}
 90→				input = "1" // fall through to connect Gmail
 91→			} else {
 92→				break
 93→			}
 94→		}
 95→
 96→		// Parse selection
 97→		var idx int
 98→		if _, err := fmt.Sscanf(input, "%d", &idx); err != nil || idx < 1 || idx > len(registry) {
 99→			fmt.Println("  Invalid selection. Try again.")
