139→	hasCRM := false
140→	for _, c := range registry {
141→		if c.Type == "crm" {
142→			if cs, ok := cfg.Connectors[c.ID]; ok && cs.Connected {
143→				hasCRM = true
144→				break
145→			}
146→		}
147→	}
148→	if !hasCRM {
149→		fmt.Println("  Tip: You can connect a CRM later with `nurge connect hubspot`")
150→	}
151→
152→	return nil
153→}
